def list_batches() -> JSONResponse:
    return JSONResponse(content={"jobs": batch_queue.list_jobs()})

server/src/image_tool/batch_routes.py :: _form_bool
def _form_bool(value: str, default: bool = True) -> bool:
    if value is None or value == "":
        return default
    return str(value).strip().lower() in {"1", "true", "yes", "on"}

server/src/image_tool/batch_routes.py :: get_batch_status
def get_batch_status(job_id: str) -> JSONResponse:
    job = batch_queue.get_job(job_id)
    if job is None:
        raise HTTPException(status_code=404, detail="Batch job not found.")
    position = batch_queue.get_queue_position(job_id)
    return JSONResponse(content=job.to_dict(queue_position=position))

server/src/image_tool/batch_routes.py :: download_batch_item
def download_batch_item(job_id: str, item_id: str) -> Response:
    item = batch_queue.get_item(job_id, item_id)
    if item is None:
        raise HTTPException(status_code=404, detail="Batch item not found.")
    if item.status != ItemStatus.COMPLETED or not item.output:
        raise HTTPException(status_code=409, detail="Item is not ready for download.")

    stem = item.source_name.rsplit(".", 1)[0] if "." in item.source_name else item.source_name
    extension = item.output_extension or "bin"
    filename = f"{stem}.{extension}"
    return Response(
        content=item.output,
        media_type=item.mime or "application/octet-stream",
        headers={"Content-Disposition": f'attachment; filename="{filename}"'},
    )

server/src/image_tool/batch_routes.py :: download_batch_zip
def download_batch_zip(job_id: str) -> Response:
    job = batch_queue.get_job(job_id)
    if job is None:
        raise HTTPException(status_code=404, detail="Batch job not found.")

    job.refresh_status()
    if job.status in {JobStatus.QUEUED, JobStatus.PROCESSING}:
        raise HTTPException(status_code=409, detail="Batch is still processing.")
    if job.completed_count == 0:
        raise HTTPException(status_code=404, detail="No completed outputs to download.")

    try:
        payload = batch_queue.build_zip(job_id)
    except KeyError as error:
        raise HTTPException(status_code=404, detail="Batch job not found.") from error

    return Response(
        content=payload,
        media_type="application/zip",
        headers={"Content-Disposition": f'attachment; filename="batch-{job_id}.zip"'},
    )
